import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Primitive Types","description":"","frontmatter":{},"headers":[],"relativePath":"archive/extra/archive/Baseline/02_primitive_types.md","filePath":"archive/extra/archive/Baseline/02_primitive_types.md"}'),n={name:"archive/extra/archive/Baseline/02_primitive_types.md"};function d(o,e,p,r,l,c){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="primitive-types" tabindex="-1">Primitive Types <a class="header-anchor" href="#primitive-types" aria-label="Permalink to &quot;Primitive Types&quot;">​</a></h1><p><strong>Baseline Feature</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented<br><strong>Test:</strong> <code>00_base_feats/02_primitive_types.vx</code></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Primitive types are the atomic building blocks of Vex. They are stack-allocated, passed by value (copy), and map directly to machine value types.</p><h2 id="integer-types" tabindex="-1">Integer Types <a class="header-anchor" href="#integer-types" aria-label="Permalink to &quot;Integer Types&quot;">​</a></h2><p>Vex provides signed (<code>i</code>) and unsigned (<code>u</code>) integers of various bit widths.</p><table tabindex="0"><thead><tr><th>Type</th><th>Bits</th><th>Range</th><th>Usage</th></tr></thead><tbody><tr><td><code>i8</code></td><td>8</td><td>-128 to 127</td><td>Small counters, wire protocols</td></tr><tr><td><code>i16</code></td><td>16</td><td>-32k to 32k</td><td>Audio samples, legacy hardware</td></tr><tr><td><code>i32</code></td><td>32</td><td>-2B to 2B</td><td><strong>Default integer type</strong></td></tr><tr><td><code>i64</code></td><td>64</td><td>-9E18 to 9E18</td><td>File sizes, timestamps, ptrs</td></tr><tr><td><code>i128</code></td><td>128</td><td>Very large</td><td>Cryptography, high-precision</td></tr><tr><td><code>u8</code></td><td>8</td><td>0 to 255</td><td>Bytes, pixels, raw data</td></tr><tr><td><code>u16</code></td><td>16</td><td>0 to 65k</td><td>Ports, hashes</td></tr><tr><td><code>u32</code></td><td>32</td><td>0 to 4B</td><td>Sizes, indexes</td></tr><tr><td><code>u64</code></td><td>64</td><td>0 to 1.8E19</td><td>Memory addresses (large)</td></tr><tr><td><code>u128</code></td><td>128</td><td>0 to 3.4E38</td><td>UUIDs, crypto types</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><code>isize</code> and <code>usize</code> depend on the target platform architecture (32-bit or 64-bit). They are typically used for array indexing and pointer arithmetic.</p></div><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let count: i32 = 100;</span></span>
<span class="line"><span>let explicit_byte: u8 = 255;</span></span>
<span class="line"><span>let uuid_part: u128 = 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF;</span></span></code></pre></div><h2 id="floating-point-types" tabindex="-1">Floating-Point Types <a class="header-anchor" href="#floating-point-types" aria-label="Permalink to &quot;Floating-Point Types&quot;">​</a></h2><p>IEEE 754 floating-point standards.</p><table tabindex="0"><thead><tr><th>Type</th><th>Bit Width</th><th>Precision</th><th>Common Use Cases</th></tr></thead><tbody><tr><td><code>f16</code></td><td>16</td><td>Half</td><td>GPU textures, ML weights</td></tr><tr><td><code>f32</code></td><td>32</td><td>Single</td><td>Graphics, game physics</td></tr><tr><td><code>f64</code></td><td>64</td><td>Double</td><td><strong>Default</strong>, SciComp, Finance</td></tr></tbody></table><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let position: f32 = 10.5; // Game coordinate</span></span>
<span class="line"><span>let precise_val: f64 = 0.1234567890123456789;</span></span></code></pre></div><h2 id="boolean" tabindex="-1">Boolean <a class="header-anchor" href="#boolean" aria-label="Permalink to &quot;Boolean&quot;">​</a></h2><p>The <code>bool</code> type represents truth values: <code>true</code> or <code>false</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let is_ready = true;</span></span>
<span class="line"><span>if is_ready {</span></span>
<span class="line"><span>    launch();</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Booleans are stored as <code>1 byte</code> (<code>i8</code>) in memory for addressability, but typically use <code>1 bit</code> in registers/SIMD masks.</p></div><h2 id="void-unit-type-nil" tabindex="-1">Void / Unit Type (<code>nil</code>) <a class="header-anchor" href="#void-unit-type-nil" aria-label="Permalink to &quot;Void / Unit Type (\`nil\`)&quot;">​</a></h2><p>Vex uses <code>nil</code> to represent the absence of a value (similar to <code>void</code> in C or <code>()</code> in Rust).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn do_nothing() {</span></span>
<span class="line"><span>    return nil; // Optional, implicit if block ends</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="real-world-usage" tabindex="-1">Real World Usage <a class="header-anchor" href="#real-world-usage" aria-label="Permalink to &quot;Real World Usage&quot;">​</a></h2><h3 id="_1-graphics-programming-u8" tabindex="-1">1. Graphics Programming (u8) <a class="header-anchor" href="#_1-graphics-programming-u8" aria-label="Permalink to &quot;1. Graphics Programming (u8)&quot;">​</a></h3><p>When processing images, <code>u8</code> is the standard type for color channels (R, G, B, A).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct Color {</span></span>
<span class="line"><span>    r: u8,</span></span>
<span class="line"><span>    g: u8,</span></span>
<span class="line"><span>    b: u8,</span></span>
<span class="line"><span>    a: u8,</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let red = Color { r: 255, g: 0, b: 0, a: 255 };</span></span></code></pre></div><h3 id="_2-high-performance-counters-usize" tabindex="-1">2. High-Performance Counters (usize) <a class="header-anchor" href="#_2-high-performance-counters-usize" aria-label="Permalink to &quot;2. High-Performance Counters (usize)&quot;">​</a></h3><p>When iterating over arrays, use <code>usize</code> to ensure maximum performance and compatibility with memory addressing.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let items = [1, 2, 3];</span></span>
<span class="line"><span>// Arrays are indexed by usize</span></span>
<span class="line"><span>for i in 0..items.() {</span></span>
<span class="line"><span>    (items[i]);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_3-financial-calculations-i64-i128" tabindex="-1">3. Financial Calculations (i64 / i128) <a class="header-anchor" href="#_3-financial-calculations-i64-i128" aria-label="Permalink to &quot;3. Financial Calculations (i64 / i128)&quot;">​</a></h3><p>Avoid floats for money. Use <code>i64</code> storing smaller units (cents) or <code>i128</code> for crypto-currencies.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Store $10.50 as 1050 cents</span></span>
<span class="line"><span>let price: i64 = 1050; </span></span>
<span class="line"><span>let quantity: i64 = 5;</span></span>
<span class="line"><span>let total = price * quantity; // 5250 cents ($52.50)</span></span></code></pre></div>`,31)])])}const g=a(n,[["render",d]]);export{u as __pageData,g as default};
